var minCharacters = function(a, b) {
    const ca = new Array(26).fill(0), cb = new Array(26).fill(0);
    for (const x of a) ca[x.charCodeAt(0) - 97]++;
    for (const x of b) cb[x.charCodeAt(0) - 97]++;
    const la = a.length, lb = b.length;
    let best = la + lb;
    for (let c = 0; c < 26; c++) best = Math.min(best, la - ca[c] + lb - cb[c]);
    const pa = new Array(27).fill(0), pb = new Array(27).fill(0);
    for (let c = 0; c < 26; c++) { pa[c + 1] = pa[c] + ca[c]; pb[c + 1] = pb[c] + cb[c]; }
    for (let t = 1; t < 26; t++) {
        best = Math.min(best, (la - pa[t]) + pb[t]);
        best = Math.min(best, (lb - pb[t]) + pa[t]);
    }
    return best;
};
